var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……네. 알겠습니다. 네.","JPN":"……はい。わかりました。はい。","ENG":"...Yes. Understood.","TWN":"……是，知道，好。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 보안국이야? 레아는 괜찮대?","JPN":"軍曹さん、保安局から？　レアは大丈夫？","ENG":"Was it the National Security, Sergeant? Is Leah okay?","TWN":"中士，是安全局打來的嗎？蕾亞還好嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 군에서 온 전화였어요.","JPN":"いいえ。軍からの電話でした。","ENG":"Nope. It was the military.","TWN":"不是，是軍隊打來的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저더러 내일까지 방위 부대에 오라네요. 건국절 행사 때 경비 인력으로 차출하려나 봐요.","JPN":"明日まで防衛部隊にくるようにって言われました。建国記念日の行事に警備として送る予定みたいです。","ENG":"Told me to report to the Defense Unit by tomorrow. I guess they're going to send me to the National Foundation Day event as a security guard.","TWN":"叫我明天前到防衛隊報到，應該是因為國慶典禮需要比較多人力戒備吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그래……. 그렇구나…….","JPN":"そうか……そうなんだね……","ENG":"Oh... I see...","TWN":"喔喔……是喔……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아는 왜 소식이 없는 걸까……? 나쁜 일에 휘말린 건 아니겠지?","JPN":"どうしてレアはなんの連絡もないのかしら……？　悪いことに巻き込まれてないわよね？","ENG":"Why hasn’t there been any news on Leah...? She hasn’t been caught up in anything horrible, has she?","TWN":"怎麼都沒有蕾亞的消息……？該不會發生什麼不好的事吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아아, 상상 친구 씨. 이럴 때 정말 싫다구요. 노골적으로 어떻게든 해 달라는 신호잖아요.","JPN":"ああ、エア友さん。こういう時が本当嫌なんだよ。明らかにどうにかしてって言う合図じゃない。","ENG":"Ahh, Mr. Imaginary Friend. This kind of situation really sucks! She’s clearly signaling to me to do something about it.","TWN":"哎呀～我想像中的朋友，我真的很討厭這種時候，這不是明擺著要我想點辦法嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 <color=#ffd34c>무공 훈장을 받은 군인이라면</color> 같은 논리에는 이제 염증이 난단 말이죠.","JPN":"でも<color=#ffd34c>勲章を授与された軍人たるもの</color>、みたいな論理はもううんざり。","ENG":"Inflammatory logic beginning with <color=#ffd34c>being a decorated soldier</color> makes me feel sick now.","TWN":"但是<color=#ffd34c>身為一位授勳的軍人</color>，聽到這種話應該會立刻上火吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"반역죄 운운한 시점에서 손가락 하나 잘못 까딱했다간 줄줄이 사형이걸랑요, 이거.","JPN":"反逆罪が言及された時点で指一本間違えたらみんな死刑なんだからね、これ。","ENG":"Since the accusation of treason came out, if we do one little thing wrong, it’s the death penalty for us all one after another.","TWN":"叛國罪這三個字一出現，就立刻將人五花大綁，然後就地正法！這樣才對吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아는……. 우리 딸은 오늘도 안 오나요……?","JPN":"レアは……私の娘は今日も来ないんですか……？","ENG":"Leah... My daughter isn’t coming today as well...?","TWN":"蕾亞……我女兒今天也不回來嗎……？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"밖에서 나쁜 짓을 하고 돌아다닐 아이는 아닌데……. 나쁜 사람들에게 잡혀간 거면…….","JPN":"外で悪ふざけをする子じゃないのに……悪い人に捕まったら……","ENG":"She isn’t the rebellious type to go out and do bad things... What if some bad people took her...","TWN":"我女兒她不是那種會在外面惹事生非的壞孩子……萬一她被壞人抓走……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"걱정 마세요, 아주머니. 레아는 무사할 거예요.","JPN":"大丈夫ですよ、おばさん。レアはきっと無事です。","ENG":"Don’t worry, Madam. Leah will be fine.","TWN":"伯母，你放心，蕾亞沒事的。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그렇지, 중사님?","JPN":"そうよね、軍曹さん？","ENG":"Isn’t that right, Sergeant?","TWN":"你說是不是，中士？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 어. ……네.","JPN":"え、あ。……はい。","ENG":"Ah, well... Right.","TWN":"蛤？喔 ……是。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"손님에게 죄송해서 어떡해…….","JPN":"お客さんに申し訳ないわ……","ENG":"With such a special guest here. I’m so sorry...","TWN":"怎麼辦，對客人這麼失禮……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"나라를 위해 싸우는 훌륭한 군인 분인데 이런 마당에 모셔서…….","JPN":"国のために戦ってくれてる立派な軍人さんなのに、こんなところに来てもらっちゃって……","ENG":"A great soldier fighting for our country and she’s here in such a bad situation...","TWN":"人家是對國家有貢獻的軍人，我們這樣招呼不周……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"……저, 중사님. 부탁 하나만 할 수 있을까?","JPN":"……あの、軍曹さん。一つお願いしてもいいかしら？","ENG":"…Sergeant. Can I ask you for a favor?","TWN":"……那個，中士，可以拜託你一件事嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨를 도와 달라는 부탁은 무리예요. 수훈자라고 해 봐야 전 결국 일개 부사관 나부랭이──","JPN":"レアさんを助けてくれという願いなら無理です。受勲者だとしても私は一介の副士官で――","ENG":"Asking me to help with Leah is a bit unreasonable. Now. Before you go calling me a war hero, really, I’m just merely a petty offic──","TWN":"如果是跟蕾亞小姐有關的，那我沒辦法。先不說我是授勳者，像我這種小咖──"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아가 무사한지 보러 가자.","JPN":"レアが無事なのか見に行こう。","ENG":"Let’s go see if Leah is alright.","TWN":"我們去看看蕾亞狀況如何吧！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"──인데 지금 뭘 보러 가자고요?","JPN":"――すけど、今何ですと？","ENG":"──er, go and see what now?","TWN":"──你說要去看什麼？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"면회는 금지라고 했지만 찾아가서 부탁하면 들어줄지도 몰라.","JPN":"面会は禁止だって言ってたけど、そこに行ってお願いすれば聞いてくれるかも知れない。","ENG":"They said no visitors are allowed, but who knows, they might let us if we go and ask.","TWN":"雖然說現在禁止會面，但直接去拜託的話或許有機會。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"이대로 계속 가만히 기다리고 있을 수만은 없잖아. 보안국 청사에 가서 얘기라도 해 볼래.","JPN":"このままじっと待っていても埒が明かないわ。保安局庁舎に言って話でもしてみる。","ENG":"I can’t just sit around and wait like this. Why not at least just go to the National Security’s office and ask?","TWN":"總不能這樣等下去吧！我想直接去安全局說說看！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니. 아니아니아니 잠깐만요. 현실 감각이 마비됐어요?","JPN":"いや。いやいやいや、待ってください。現実感覚がマヒしてませんか？","ENG":"Wait, wait, wait, just hold on for a second. Are you out of mind?","TWN":"什麼？不行不行不行！且慢！你腦袋沒問題吧？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레아 씨는 지금 반역자 취급을 받고 있어요. 잘못하면 안젤라 씨도 동조자로 몰린다고요.","JPN":"レアさんは今反逆者扱いされてるんですよ。一歩間違えたらアンジェラさんも共犯になります。","ENG":"Leah is currently seen as a traitor. If you mess up, they might see you as an accomplice.","TWN":"蕾亞小姐現在的罪名是叛國罪，萬一有個什麼差錯，你很可能會被視為是共犯欸！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그래도 괜찮아.","JPN":"それでも大丈夫。","ENG":"That’s okay.","TWN":"我無所謂。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뭐가 괜찮아요? 안젤라 씨가 카운터라서요?","JPN":"何が大丈夫なんですか？　アンジェラさんがカウンターだから？","ENG":"What do you mean okay? Because you’re a Counter?","TWN":"什麼無所謂？因為你是制裁者嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_PRIDE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"카운터도 죽을 때는 죽어요. 안젤라 씨가 저보다 한참 잘난 카운터란 건 알지만…….","JPN":"カウンターも死ぬ時には死にますよ。アンジェラさんが私よりもっとすごいカウンターってことはわかりますけど……","ENG":"Counters aren’t immortal, you know. I know you’re a lot stronger than me, but...","TWN":"制裁者也是會死的好嗎！我知道你比我厲害啦……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아주머니, 저 잠시 나갔다 올게요.","JPN":"おばさん、ちょっとお出かけしてきます。","ENG":"Madam, I need to head out for just a minute or two.","TWN":"伯母，我要出去一下，"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L49_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"제가 없는 동안 집에 얌전히 계실 거죠?","JPN":"私がいない間、家でおとなしくできますよね？","ENG":"You’ll just stay here and rest at home while I’m away, right?","TWN":"我不在的時候，你要乖乖在家喔！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으, 으응……. 그럼요……!","JPN":"う、うん……もちろんです……！","ENG":"Y-yes, of course…","TWN":"呃嗯嗯……好……！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"혼자여도, 잘 지낼 수 있어요…….","JPN":"一人でも、大丈夫ですよ……","ENG":"I’ll be fine by myself...","TWN":"我會自己乖乖在家……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……친구가 쌍으로 사람 말 더럽게 안 듣네. 진짜.","JPN":"……二人揃って人の言うことを聞かないなぁ。まったく。","ENG":"...Guess the two don’t listen at all. Seriously.","TWN":"……你們真不愧是好朋友，都一樣沒在聽人講話的！"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"보안국에 오해 받을까 봐 걱정돼서 그래?","JPN":"保安局から誤解されるのが心配なの？","ENG":"Are you worried there might be a misunderstanding at the National Security?","TWN":"你是擔心安全局會誤會你嗎？"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"괜찮아. 중사님은 방위 부대로 가. 길은 내가 가르쳐 줄게.","JPN":"大丈夫よ。軍曹さんは防衛部隊に行って。私が道を教えてあげる。","ENG":"It will be fine. Just go to the Defense Unit. Here, I’ll show you the way,","TWN":"沒關係，那你就去防衛隊吧，我告訴你怎麼走。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"반군들이 나타났을 때 마지막까지 같이 있어 줘서 고마웠어.","JPN":"反乱軍が現れた時に最後まで一緒にいてくれてありがとう。","ENG":"Oh, and back when the rebels showed up, thank you so much for staying with me to the end.","TWN":"謝謝你在叛軍出現時，沒有扔下我們不管。"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"DORMITORY_3","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이럴 때 넘어가면 큰일납니다.","JPN":"こういう時ほだされると大変なことになる。","ENG":"Uh oh, she can’t coax me like this.","TWN":"這種時候絕對不能心軟！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"인간은 영악하거든요. 저런 감성 자극하는 말들로 동정심을 유발시킨 다음 맘대로 휘두른다고요.","JPN":"人間はずる賢いからね。あんな風に感性を刺激する言葉で同情心を煽った後に好き放題振り回すんです。","ENG":"People are so manipulative. She’s just using those words to get you to sympathize, next thing you know you’ll be doing whatever she wants you to.","TWN":"人是很狡猾的，先用那種話情勒你，再利用你的同情心來使喚你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그리고 제가 왜 방위 부대로 가요? 브로커에게 기부한 것도 아니고?","JPN":"それになんで私が防衛部隊なんかに行くの？　ブローカーに寄付したわけでもないのに。","ENG":"And why even go to the Defense Unit? I didn’t simply donate my money to the smuggler.","TWN":"而且我幹嘛要去防衛隊？我的錢又不是白白捐給人蛇仲介的？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이번이 이 나라를 벗어날 마지막 기회라고요, 상상 친구 씨. 바로 브로커를 찾아서…….","JPN":"これがこの国から離れるラストチャンスです、エア友さん。早速ブローカーを探して……","ENG":"Mr. Imaginary Friend, this is my last chance to get out of the country. I have to find that smuggler and...","TWN":"這次是我脫離這個國家最後的機會，我想像中的朋友，還是趕快去找人蛇仲介……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"여기가 보안국 청사야.","JPN":"ここが保安局庁舎よ。","ENG":"Here it is. The Department of National Security’s main office.","TWN":"這裡就是安全局的大樓。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"허어…………. 나 진짜 등신인가 봐.","JPN":"はあ…………私って本当にバカじゃないかな。","ENG":"Huh... I really am a helpless idiot aren’t I?","TWN":"哀…………我真的是蠢的可以。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"자책하는 건 나쁜 버릇이야, 중사님.","JPN":"自分を責めるのは悪い癖よ、軍曹さん。","ENG":"It’s a bad habit to always blame yourself, Sergeant.","TWN":"自責不是好的習慣喔，中士。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그래도 중사님이 같이 와 줘서 다행이야. 혼자서는 솔직히 조금 무서웠거든.","JPN":"でも軍曹さんが一緒に来てくれてよかった。正直一人ではちょっと怖かったの。","ENG":"Still, I’m glad you came with me, Sergeant. To be honest, the thought of going alone was a little frightening.","TWN":"不過還是很謝謝你跟我一起來，說真的，自己一個人還真有點怕呢。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"뉘예, 뉘예. 어련히 그러셨겠죠…….","JPN":"へい、へい。そうでしょうとも……","ENG":"Yes, yes. Sure it was...","TWN":"是是是，肯定是會怕的嘛……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아. 저기 계신 군인 분들에게 여쭤 보자.","JPN":"あ、あそこの軍人さんたちに聞いてみよう。","ENG":"Ah, Let’s go ask those soldiers over there.","TWN":"去問問那邊的軍人吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"군인들이 뭐래요?","JPN":"なんて言われましたか？","ENG":"What did they say?","TWN":"他們怎麼說？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L33_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"썩 꺼지지 않으면 쏴 버리겠대.","JPN":"今すぐ消えないと撃つって。","ENG":"“Go away or we’ll shoot.”","TWN":"他們說再不滾的話就立刻射爆你。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"안젤라 씨가 예뻐서 다행이네요. 덕분에 사이 좋게 심문실에 끌려가지 않았잖아요.","JPN":"アンジェラさんが美人でよかったですね。おかげさまで仲良く尋問室に連れていかれることもなかったじゃないですか。","ENG":"It’s a good thing you’re so pretty. Otherwise they would have probably hauled us off to the interrogation room instead.","TWN":"幸好你長得美，不然很可能立刻被帶到審訊室。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"그렇지만 이대로 돌아가면 레아는…….","JPN":"でもこのまま帰ればレアは……","ENG":"But if we just go back now, Leah...","TWN":"但我們也不能空手而歸……"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……에휴.","JPN":"……はあ。","ENG":"Ugh...","TWN":"……哀哀。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래요. 기왕 여기까지 왔으니까 무사한지만 확인하고 가죠.","JPN":"いいですよ。ここまで来たんだし、無事かどうかだけ確認して帰りましょう。","ENG":"Fine. Since we came all this way, we should at least make sure she’s unharmed.","TWN":"好吧，來都來了，就確認她是否無恙再走吧！"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"정말? 어떻게?","JPN":"本当？　どうやって？","ENG":"Oh? But how?","TWN":"真的嗎？要怎麼確認？"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"일단은 D등급 언저리긴 해도 듣는 건 남들보다 조금 나은 편이거든요.","JPN":"Dランクあたりですけど、一応耳は他の人よりいい方ですから。","ENG":"Well, I’m only around a D grade, but my listening is a little better than others.","TWN":"好歹我也在D級邊緣，聽力比別人好一點。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우선 뒷골목으로 돌아가요. 건물 안 목소리까지 들으려면 조용한 곳에서 집중해야 하니까.","JPN":"まず裏路地へ回りましょう。建物の中の声まで聞くためには、静かなところで集中する必要がありますから。","ENG":"Let’s head around back towards that alley. I’ll need somewhere quiet to hear the voices in the building.","TWN":"我們先回到巷子裡吧，我要找一個安靜的地方，才能專心聽建築物裡的聲音。"},"stage":{"bg":"GRONIA_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 여기부터는 인적도 없고 조용한 것 같아.","JPN":"軍曹さん、ここからは人の気配もないし静かだよ。","ENG":"Sergeant, it looks like there’s no one around here and it seems pretty quiet.","TWN":"中士，這裡都沒人，很安靜。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네. 이쯤이면 충분하겠어요.","JPN":"はい。ここら辺で十分です。","ENG":"Yeah. This should be good enough.","TWN":"嗯，這裡應該可以。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"후우…….","JPN":"ふう……","ENG":"Whew...","TWN":"呼……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지하실에 있나 봐요. 목소리는……. 많이 지친 것 같아요.","JPN":"地下室にいるみたいです。声は……結構疲れてるみたいですね。","ENG":"Sounds like she’s in the basement. Her voice... It sounds pretty exhausted.","TWN":"她好像在地下室，聲音……聽起來很累的樣子。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"지치다니? 혹시 다친 거 아닐까?","JPN":"疲れる？　もしかしたら怪我でもしたんじゃないかな？","ENG":"Exhausted? She isn’t hurt, is she?","TWN":"很累嗎？還是因為受傷的關係？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니라고 하고 싶지만…… 잘은 모르겠어요.","JPN":"違うって言いたいところですけど……よくわかりません。","ENG":"I’d like to say no, but... I’m not sure.","TWN":"我也不希望是因為受傷的關係……但原因我無法確定。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"꼭 해코지를 해야 말하고 싶어지게 만들 수 있는 것도 아니고.","JPN":"必ず痛めつける方法で自白させるわけでもないですし。","ENG":"Harming her isn’t the only way to get her to talk.","TWN":"不過應該不至於嚴刑逼共吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아프면 보안국 사람들이 치료는 해 줄까……?","JPN":"怪我したら保安局の人たちが手当てをしてくれるのかな……？","ENG":"If she’s hurt, will the National Security treat her...?","TWN":"而且如果有哪裡不舒服，安全局的人應該會送她去醫院……吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……글쎄요. 솔직히 거짓말을 하고 싶은데, 상대가 보안국이라.","JPN":"……どうでしょう。正直言ってウソをつきたくても、相手が保安局なんで。","ENG":"...Well. I’d love to be able to lie to you, but it’s the National Security we’re talking about.","TWN":"……這個嘛，因為對方是安全局，所以我不敢保證。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"으음…….","JPN":"ううん……","ENG":"Mmm...","TWN":"嗯嗯……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"중사님, 우리 몰래 들어가 보자.","JPN":"軍曹さん、こっそり入ってみようよ。","ENG":"Sergeant, let’s sneak in.","TWN":"中士，我們偷溜進去吧！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"레아는 내가 오랫동안 돌봐 온 인간이야. 무사한지 언니 눈으로 직접 확인할래.","JPN":"レアは私が長い間、面倒を見て来た人間なの。無事かどうかお姉ちゃんの目で確かめる。","ENG":"I’ve been looking after that human for a long time, I need to see with my own eyes that she’s okay.","TWN":"蕾亞是我照顧很久的人類，我必須親眼確認她沒事。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"미친 소리 하지 마세요. 경찰서 들어가 본 적도 없는데 정보 기관에요?","JPN":"冗談言わないでください。警察署すら入ったことないのに情報機関にですか？","ENG":"Are you crazy? I’ve never even been inside a police station let alone the intelligence agency.","TWN":"你在胡說八道什麼！連警察局都沒去過，現在還想闖入情報機關？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여긴 사실상 치외 법권이에요. 무단 침입하면 총 맞아 죽어도 아무 말 못해요.","JPN":"ここは実際上の治外法権です。むやみに入って銃に撃たれて死んでも文句は言えません。","ENG":"This place is practically exempt from any law. If you break in without permission, they can just immediately kill you without any consequences.","TWN":"其實這裡屬於治外法權，擅闖進去的話，就算被開槍打死也沒法可管的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"언니랑 같이 다니면 괜찮아. 아무리 큰 상처도 금방 아물게 해 줄 수 있어.","JPN":"お姉ちゃんと一緒なら大丈夫よ。いくら大怪我をしてもすぐ治してあげられる。","ENG":"If you go with me, you’ll be okay. No matter how big the wound is, it will quickly be healed.","TWN":"我們一起行動就沒問題啦，不管你傷得多重，我都可以立刻治好你。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 치유 능력자셨구나. 이거 귀한 분을 몰라 뵙고.","JPN":"あ、癒しの能力者だったんですね。これはこれは、失礼しました。","ENG":"Ahh, you’re a healer type. I should’ve realized that earlier.","TWN":"原來你的特殊能力是治癒，真是失敬失敬。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데 그거 아세요? 전차포 잘못 맞으면 사람이 이빨 빠진 퍼즐 된다는 거?","JPN":"でも、知ってますか？　人が戦車砲に当たったら、ピースが欠けたパズルのようになるんです。","ENG":"But you know what? People literally turn into puzzle pieces when blown by a massive tank.","TWN":"但你知道嗎？要是被坦克砲打到的話，是會瞬間粉身碎骨的欸？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전차까지 대령해 둔 요새인데 어떤 정신 나간 놈이 여길 들이받아요?","JPN":"戦車まで待機させてる要塞なのに、どこのバカがここを攻撃するんですか。","ENG":"This place is practically a fortress full of tanks. You’d have to be insane to try to sneak in.","TWN":"而且最近還有戰車進駐，哪個神經病會想擅闖這裡啦！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"……방금 그 소리 들었어요?","JPN":"……今の音、聞きました？","ENG":"...Did you hear that?","TWN":"……你有聽到剛剛的聲音嗎？"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"응, 대로 쪽이야!","JPN":"うん、大通りの方だよ！","ENG":"Yeah, towards the main street!","TWN":"嗯，在大馬路上！"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BASS_HARMONY_NULL_HIDE","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아니, 반대 방향으로 가야지 왜 그리로 뛰어가요?!","JPN":"いや、反対でしょ！　なんでそっちに走るんですか！？","ENG":"What? You’re supposed to go in the opposite direction! Why are you running that way?!","TWN":"你是不是跑錯方向啦？應該要往反方向吧？！"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};